import{_ as t,o as a,c as i,a3 as o}from"./chunks/framework.CjquFG0V.js";const h=JSON.parse('{"title":"49. Examination Leave","description":"","frontmatter":{"title":"49. Examination Leave","eba":"Doctors in Training 2022-2026","topics":["leave","study-leave","hours","rosters"]},"headers":[],"relativePath":"ebas/doctors-in-training/education-pd/49-examination-leave.md","filePath":"ebas/doctors-in-training/education-pd/49-examination-leave.md"}'),n={name:"ebas/doctors-in-training/education-pd/49-examination-leave.md"};function r(s,e,c,d,p,l){return a(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="_49-examination-leave" tabindex="-1">49. Examination Leave <a class="header-anchor" href="#_49-examination-leave" aria-label="Permalink to &quot;49. Examination Leave&quot;">​</a></h1><p><strong>49.1</strong> Entitlement</p><p>A Doctor is entitled to a total amount of paid Examination Leave not exceeding eight rostered working days in any one year as described at clause 49.2 below. Use for a purpose not described at clause 49.2 below is not permitted by this clause.</p><p><strong>49.2</strong> Use of Examination Leave</p><p><strong>(a)</strong> Doctors are entitled to utilise their paid Examination Leave of eight days in the following ways:</p><p><strong>(i)</strong> to attend any examination (within Australia or New Zealand):</p><p>A. necessary to obtain Australian Medical Council (AMC) Registration; or</p><p>B. necessary to obtain a Higher Qualification as defined at subclause 3.1(q) (Definitions – Higher Qualifications) of this Agreement; or</p><p>C. to enable post graduate studies in the United States; or</p><p>D. necessary to obtain a relevant qualification as defined at subclause 49.5.</p><p><strong>(ii)</strong> to provide for at least three clear calendar days’ off immediately prior to each examination, with Examination Leave to be paid for days that would have been worked according to a projected roster; or</p><p><strong>(iii)</strong> to attend a conference or seminar, which is a requirement for sitting an examination that leads to AMC Registration or a Higher Qualification as defined at subclause 3.1(q) of this Agreement.</p><p><strong>(b)</strong> The period of leave must include travel time to and from the centre at which the examination is held.</p><p><strong>49.3</strong> Notice of Taking Examination Leave</p><p>The Doctor must give the Health Service’s Director of Medical Services at least four weeks’ written notice of their intention to access Examination Leave.</p><p><strong>49.4</strong> Payment Calculation</p><p>Payment of Examination Leave under this clause 49 must be made consistent with the roster or projected roster, excluding overtime and penalties.</p><p><strong>49.5</strong> Relevant Qualification</p><p><strong>(a)</strong> The main criteria for considering relevance for the purpose of subclause 49.2(a)(i)D are:</p><p><strong>(i)</strong> the nature of the education; and</p><p><strong>(ii)</strong> that the education is aligned to a recognised area of medical practice having regard to:</p><p>A. the clinical or other area of work of the Doctor; and</p><p>B. the classification and position description of the Doctor.</p><p>Plain language terms: exam leave.</p>',24)])])}const m=t(n,[["render",r]]);export{h as __pageData,m as default};
